@Suppress("HtmlUnknownTarget", "HtmlRequiredAltAttribute")
class TemplateManagerHashtagTest {

    @Test
    fun `parseSourcesToFileScheme - img with hashtag in filename`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        // Test unencoded # (legacy format from Anki Desktop)
        val result = parseSourcesToFileScheme("<img src=\"test#image.jpg\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/test%23image.jpg">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - img with encoded hashtag in filename`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        // Test encoded %23 (proper encoding)
        val result = parseSourcesToFileScheme("<img src=\"test%23image.jpg\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/test%23image.jpg">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - audio with hashtag in filename`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<audio src=\"sound#file.mp3\"></audio>", mediaDir)
        assertEquals("""<audio src="file:///$mediaDir/sound%23file.mp3"></audio>""", result)
